import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Item, Location, MovementType } from '../../core/models';

/**
 * Record a stock movement (clerk + manager). Supports IN, OUT and TRANSFER;
 * the `?type=` query param deep-links a pre-selected movement type. IN needs a
 * destination, OUT a source, TRANSFER both. An optional note can be attached.
 */
@Component({
  selector: 'app-movement-record',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './movement-record.component.html',
  styleUrl: './movement-record.component.css',
})
export class MovementRecordComponent implements OnInit {
  readonly saving = signal(false);
  readonly error = signal<string | null>(null);
  readonly done = signal(false);

  readonly types: MovementType[] = ['IN', 'OUT', 'TRANSFER'];
  readonly type = signal<MovementType>('IN');

  readonly items = signal<Item[]>([
    { id: 'i1', sku: 'SKU-1001', name: 'Steel Bolt M6', unit: 'pcs', reorderAt: 100, onHand: 340 },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', reorderAt: 200, onHand: 85 },
    { id: 'i3', sku: 'SKU-1003', name: 'PVC Pipe 20mm', unit: 'pcs', reorderAt: 50, onHand: 12 },
    { id: 'i6', sku: 'SKU-1006', name: 'Rubber Gasket 50mm', unit: 'pcs', reorderAt: 80, onHand: 0 },
  ]);

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);

  model = { itemId: '', fromLocId: '', toLocId: '', qty: 1, note: '' };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParamMap.subscribe((p) => {
      const t = (p.get('type') ?? '').toUpperCase() as MovementType;
      if (this.types.includes(t)) this.type.set(t);
      const itemId = p.get('itemId');
      if (itemId) this.model.itemId = itemId;
    });
  }

  setType(t: MovementType): void {
    this.type.set(t);
    this.error.set(null);
  }

  get needsFrom(): boolean {
    return this.type() === 'OUT' || this.type() === 'TRANSFER';
  }
  get needsTo(): boolean {
    return this.type() === 'IN' || this.type() === 'TRANSFER';
  }

  submit(): void {
    if (!this.model.itemId) {
      this.error.set('Select an item.');
      return;
    }
    if (this.needsFrom && !this.model.fromLocId) {
      this.error.set('Select a source location.');
      return;
    }
    if (this.needsTo && !this.model.toLocId) {
      this.error.set('Select a destination location.');
      return;
    }
    if (this.type() === 'TRANSFER' && this.model.fromLocId === this.model.toLocId) {
      this.error.set('Source and destination must differ.');
      return;
    }
    if (!this.model.qty || this.model.qty <= 0) {
      this.error.set('Quantity must be greater than zero.');
      return;
    }
    this.error.set(null);
    this.saving.set(true);
    // Mock persist — flash a confirmation, then return to the items list.
    this.saving.set(false);
    this.done.set(true);
  }

  recordAnother(): void {
    this.done.set(false);
    this.model = { itemId: '', fromLocId: '', toLocId: '', qty: 1, note: '' };
  }

  goToItems(): void {
    this.router.navigate(['/']);
  }
}
